const fs = require('fs');
const path = require('path');
const { Schema } = require('@dbcube/schema-builder');
const ConfigFileUtils = require('./../../../utils/ConfigFileUtils');
const { loadHistory, saveHistory, hashFile, collectAlterFiles, buildReverse } = require('../../migrate/lib');

/**
 * dbcube run table:alter [--dry-run] [--all]
 * Applies PENDING .alter.cube migrations (tracked in dbcube/migrations.json).
 * --dry-run: prints the SQL without executing anything.
 * --all: re-runs every alter file, ignoring the history (legacy behavior).
 */
async function main() {
  const args = process.argv.slice(2);
  const dryRun = args.includes('--dry-run');
  const runAll = args.includes('--all');

  try {
    const history = loadHistory();
    const appliedNames = new Set(history.applied.map(a => a.file));
    const allFiles = collectAlterFiles();

    // Only pending files (unless --all)
    const targetFiles = runAll ? allFiles : allFiles.filter(f => !appliedNames.has(path.basename(f)));

    if (targetFiles.length === 0) {
      console.log('\n✅ No pending migrations — everything up to date.');
      console.log('   (use --all to re-run applied alter files)\n');
      return;
    }

    const targetNames = targetFiles.map(f => path.basename(f));
    const configuredDatabases = await ConfigFileUtils.getConfiguredDatabases();

    let totalErrors = 0;
    for (const config of configuredDatabases) {
      const schema = new Schema(config.name);
      try {
        const result = await schema.executeAlters(targetNames, { dryRun });
        totalErrors += result?.errors ?? 0;
      } catch (e) {
        if (!String(e.message).includes('no .alter.cube files')) throw e;
      }
    }

    // Una migración que falló NO puede quedar registrada como aplicada:
    // jamás se reintentaría y la DB quedaría desincronizada del historial
    if (totalErrors > 0) {
      console.error(`\n❌ ${totalErrors} error(s) applying migrations — batch NOT recorded.`);
      console.error('   Fix the .alter.cube files and run table:alter again.\n');
      process.exit(1);
    }

    // Record history (skip on dry-run)
    if (!dryRun) {
      const batch = history.lastBatch + 1;
      for (const file of targetFiles) {
        const base = path.basename(file);
        if (appliedNames.has(base)) continue;
        const content = fs.readFileSync(file, 'utf8');
        const { reverse } = buildReverse(content);
        history.applied.push({
          file: base,
          hash: hashFile(file),
          batch,
          applied_at: new Date().toISOString(),
          reverse, // null => irreversible
        });
      }
      history.lastBatch = batch;
      saveHistory(history);
      console.log(`\n📋 Recorded batch ${batch} in dbcube/migrations.json`);
      console.log('   Status: npx dbcube migrate:status · Rollback: npx dbcube migrate:rollback\n');
    }
  } catch (error) {
    if (error.message.includes("reading 'init'")) {
      console.error('❌ Configuracion de base de datos no encontrada\n');
      console.error('Ejecute el comando para crear una nueva base de datos:');
      console.error(`\tdbcube run database:create`);
      console.error('\nO verifique que la base de datos este configurada en el archivo dbcube.config.js\n');
      process.exit(1);
    } else if (error.message.includes("There are no .alter.cube files")) {
      console.error('❌ No se encontraron archivos .alter.cube en la carpeta dbcube/\n');
      console.error('Crea un archivo .alter.cube con la siguiente estructura:');
      console.error('');
      console.error('  @database("nombre_db");');
      console.error('  @table("nombre_tabla");');
      console.error('');
      console.error('  @addColumn({');
      console.error('      nueva_columna: {');
      console.error('          type: "varchar";');
      console.error('          length: "255";');
      console.error('          options: ["not null"];');
      console.error('      };');
      console.error('  });');
      console.error('');
      process.exit(1);
    } else {
      console.error('Error:', error.message);
      process.exit(1);
    }
  }
}

main().catch(console.error);
